prompt --application/shared_components/logic/application_processes/add_user
begin
wwv_flow_imp_shared.create_flow_process(
 p_id=>wwv_flow_imp.id(65706035276107866044)
,p_process_sequence=>1
,p_process_point=>'AFTER_LOGIN'
,p_process_name=>'Add User'
,p_static_id=>'add-user'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'-- create game user ID',
'-- query game_users table to check for existing user',
'-- if yes, return PK as user_id',
'-- if no, add new user to game_users',
'declare',
'    l_user_id number;',
'begin',
'    select id into l_user_id from game_users where username = :APP_USER;',
'',
'    :USER_ID := l_user_id;',
'',
'    exception',
'        when no_data_found then',
'        insert into game_users ',
'                (username)',
'            values ',
'                (:APP_USER)',
'            returning ',
'                id into :USER_ID;',
'end;'))
,p_process_clob_language=>'PLSQL'
,p_version_scn=>'40632111356431'
);
end;
