,p_process_sequence=>80
,p_process_point=>'BEFORE_HEADER'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Set Favorite Label'
,p_static_id=>'set-favorite-label'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'  l_fav varchar2(1);',
'begin',
'  begin',
'    select favorite_yn into l_fav',
'      from watchlist',
'     where game_id = to_number(:P3_ID)',
'       and user_id = :USER_ID;',
'  exception',
'    when no_data_found then l_fav := ''N'';',
'  end;',
'  ',
'  if l_fav = ''Y'' then',
'    apex_util.set_session_state(''P3_FAV_LABEL'', ''Remove from Favorites'');',
'  else',
'    apex_util.set_session_state(''P3_FAV_LABEL'', ''Add to Favorites'');',
'  end if;',
'end;'))
,p_process_clob_language=>'PLSQL'
,p_internal_uid=>2897993417128451229
,p_created_on=>wwv_flow_imp.dz('20260525111712Z')
,p_updated_on=>wwv_flow_imp.dz('20260525111712Z')
,p_created_by=>'ANASTASHS350@GMAIL.COM'
,p_updated_by=>'ANASTASHS350@GMAIL.COM'
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(6517524932627218888)
,p_process_sequence=>80
,p_process_point=>'ON_SUBMIT_BEFORE_COMPUTATION'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Toggle Favorite'
,p_static_id=>'toggle-favorite'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'  l_favorite varchar2(1) := ''N'';',
'  l_count    number;',
'begin',
'  begin',
'    select favorite_yn into l_favorite',
'      from watchlist',
'     where game_id = to_number(:P3_ID)',
'       and user_id = :APP_USER;',
'  exception',
'    when no_data_found then',
'      raise_application_error(-20001, ''Add the game to your Watchlist first!'');',
'  end;',
'',
'  select count(*) into l_count',
'    from watchlist',
'   where user_id = :APP_USER',
'     and favorite_yn = ''Y'';',
'',
'  if l_favorite = ''Y'' then',
'    update watchlist',
'       set favorite_yn = ''N''',
'     where game_id = to_number(:P3_ID)',
'       and user_id = :APP_USER;',
'  elsif l_count < 4 then',
'    update watchlist',
'       set favorite_yn = ''Y''',
'     where game_id = to_number(:P3_ID)',
'       and user_id = :APP_USER;',
'  else',
'    raise_application_error(-20001, ''You can only have 4 favorite games!'');',
'  end if;',
'end;'))
,p_process_clob_language=>'PLSQL'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(6517524778966218887)
,p_internal_uid=>2897993078480451225
,p_created_on=>wwv_flow_imp.dz('20260523180735Z')
,p_updated_on=>wwv_flow_imp.dz('20260524150632Z')
,p_created_by=>'ANASTASHS350@GMAIL.COM'
,p_updated_by=>'ANASTASHS350@GMAIL.COM'
);
wwv_flow_imp_page.create_page_process(
 p_id=>wwv_flow_imp.id(65379849558323693698)
,p_process_sequence=>70
,p_process_point=>'AFTER_SUBMIT'
,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'Update game'
,p_static_id=>'update-game'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'update watchlist',
'   set watched_yn = ''Y'',',
'       watched = SYSDATE',
